#include<iostream>
#include<cmath>
#include<algorithm>
using namespace std;

int maxn = -1, s = 0;

int v[43];
bool dp[803][803];

int sum(int a, int b, int c)
{
	double p = (a + b + c) / 2.0;
	double s = sqrt(p * (p - a) * (p - b) * (p - c));
	return s * 100;
}

bool chk(int a, int b, int c)
{
	if(max(a, max(b, c)) * 2 < a + b + c) return 1;
	return 0;
}

int main() {
	int n;
	cin >> n;
	for(int i = 1; i <= n; i++)
	{
		cin >> v[i];
		s += v[i];
	}
	dp[0][0] = 1;
	for(int i = 1; i <= n; i++)
		for(int j = 800; j >= 0; j--)
			for(int k = 800; k >= 0; k--)
			{
				int l = s - j - k;
				if(j >= v[i]) dp[j][k] |= dp[j - v[i]][k] + v[i];
				if(k >= v[i]) dp[j][k] |= dp[j][k - v[i]] + v[i];
				if(dp[j][k] && chk(j, k, l)) maxn = max(maxn, sum(j, k, l));
			}
	cout << maxn;
    return 0;
}
